export interface Param {
  name: string;
  type: string;
  req: boolean;
  desc: string;
  location?: 'body' | 'query' | 'path'; // defaults to 'body' for POST, 'query' for GET
}

export interface Endpoint {
  id: string;
  category: string;
  name: string;
  methods: string[];
  path: string;
  version: string;
  desc: string;
  page: number;
  params: Param[];
  request: string;
  response: string;
}

